import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for LeakyReLU with vectorized memory access
leaky_relu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

template<typename T>
__global__ void leaky_relu_kernel(const T* input, T* output, float negative_slope, int64_t size) {
    int64_t idx = blockIdx.x * blockDim.x * 4 + threadIdx.x * 4;

    if (idx + 3 < size) {
        // Vectorized load and store for better memory bandwidth utilization
        T in0 = input[idx];
        T in1 = input[idx + 1];
        T in2 = input[idx + 2];
        T in3 = input[idx + 3];

        output[idx] = in0 > 0 ? in0 : static_cast<T>(negative_slope * in0);
        output[idx + 1] = in1 > 0 ? in1 : static_cast<T>(negative_slope * in1);
        output[idx + 2] = in2 > 0 ? in2 : static_cast<T>(negative_slope * in2);
        output[idx + 3] = in3 > 0 ? in3 : static_cast<T>(negative_slope * in3);
    } else {
        // Handle remaining elements
        for (int i = 0; i < 4; i++) {
            if (idx + i < size) {
                T val = input[idx + i];
                output[idx + i] = val > 0 ? val : static_cast<T>(negative_slope * val);
            }
        }
    }
}

torch::Tensor leaky_relu_cuda(torch::Tensor input, float negative_slope) {
    auto output = torch::empty_like(input);
    int64_t size = input.numel();

    // Optimize block size based on tensor size
    const int block_size = 256;
    const int num_blocks = (size + block_size * 4 - 1) / (block_size * 4);

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "leaky_relu_cuda", ([&] {
        leaky_relu_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            negative_slope,
            size
        );
    }));

    return output;
}
"""

leaky_relu_cpp_source = """
torch::Tensor leaky_relu_cuda(torch::Tensor input, float negative_slope);
"""

# Compile the inline CUDA code
leaky_relu_cuda_module = load_inline(
    name="leaky_relu_cuda",
    cpp_sources=leaky_relu_cpp_source,
    cuda_sources=leaky_relu_source,
    functions=["leaky_relu_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcudart"],
    with_cuda=True,
    extra_include_paths=[],
)

class ModelNew(nn.Module):
    """
    Optimized model that performs LeakyReLU activation using custom CUDA kernel.
    """
    def __init__(self, negative_slope: float = 0.01):
        """
        Initializes the optimized LeakyReLU module.

        Args:
            negative_slope (float, optional): The negative slope of the activation function. Defaults to 0.01.
        """
        super(ModelNew, self).__init__()
        self.negative_slope = negative_slope
        self.leaky_relu_cuda = leaky_relu_cuda_module

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies optimized LeakyReLU activation to the input tensor using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of any shape.

        Returns:
            torch.Tensor: Output tensor with LeakyReLU applied, same shape as input.
        """
        if x.is_cuda:
            return self.leaky_relu_cuda.leaky_relu_cuda(x, self.negative_slope)
        else:
            # Fallback to PyTorch implementation for CPU tensors
            return torch.nn.functional.leaky_relu(x, negative_slope=self.negative_slope)

